CREATE TABLE foods (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL, description TEXT, price REAL NOT NULL, image_url TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP); CREATE TABLE orders (id INTEGER PRIMARY KEY AUTOINCREMENT, food_id INTEGER NOT NULL, quantity INTEGER NOT NULL, total_price REAL NOT NULL, customer_name TEXT NOT NULL, customer_address TEXT NOT NULL, status TEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (food_id) REFERENCES foods(id)); CREATE INDEX idx_orders_food_id ON orders(food_id);